207→        return new Declarables(
208→                BindingBuilder.bind(userAdminChangeQueue()).to(apitableEventNotificationExchange()).with(APITABLE_USER_ADMIN_CHANGE_ROUTING_KEY),
209→                BindingBuilder.bind(userSpaceChangeQueue()).to(apitableEventNotificationExchange()).with(APITABLE_USER_SPACE_CHANGE_ROUTING_KEY),
210→                BindingBuilder.bind(nodeCreateQueue()).to(apitableEventNotificationExchange()).with(APITABLE_NODE_CREATE_ROUTING_KEY),
211→                BindingBuilder.bind(unitMembershipChangeQueue()).to(apitableEventNotificationExchange()).with(APITABLE_UNIT_MEMBERSHIP_CHANGE_ROUTING_KEY),
212→                BindingBuilder.bind(aioTeamOperateQueue()).to(aioTeamOperateExchange()).with(AIO_TEAM_OPERATE_KEY),
213→                BindingBuilder.bind(spaceNodeMigrationQueue()).to(spaceNodeMigrationExchange()).with(SPACE_NODE_MIGRATION_KEY),
214→                BindingBuilder.bind(announcementQueue()).to(announcementExchange()).with(ANNOUNCEMENT_KEY).noargs(),
215→                BindingBuilder.bind(thirdAppUploadUpdateQueue()).to(thirdAppUploadUpdateExchange()).with(THIRD_APP_UPLOAD_UPDATE_ROUTING_KEY)
216→
217→        );
218→    }
219→
220→}
