 76→    /**
 77→     * 接受消息
 78→     *
 79→     * @param session
 80→     * @param message
 81→     * @throws Exception
 82→     */
 83→    @Override
 84→    public void handleMessage(WebSocketSession session, WebSocketMessage<?> message) throws Exception {
 85→        String messageContent = message.getPayload().toString();
 86→        log.debug("收到消息: {}", messageContent);
 87→
 88→
 89→        // 处理心跳消息
 90→        if ("pong".equals(messageContent) || "ping".equals(messageContent)) {
 91→            handleHeartbeatMessage(session, messageContent);
 92→            return;
 93→        }
 94→        // 处理其他业务消息
 95→        try {
 96→            JSONObject messageObj = JSONUtil.parseObj(messageContent);
 97→            String type = messageObj.getStr("type");
 98→
 99→            if ("heartbeat".equals(type)) {
100→                handleHeartbeatMessage(session, "pong");
101→            }
102→        } catch (Exception e) {
103→            log.error("处理消息失败: {}", e.getMessage(), e);
104→        }
105→    }
106→
107→
108→    /**
109→     * 处理心跳消息
110→     */
111→    private void handleHeartbeatMessage(WebSocketSession session, String messageContent) {
112→        try {
113→            if ("ping".equals(messageContent)) {
114→                // 客户端发来ping，回复pong
115→                session.sendMessage(new TextMessage("pong"));
116→                log.debug("收到ping，回复pong: {}", session.getId());
117→            } else if ("pong".equals(messageContent)) {
118→                // 客户端回复pong，记录心跳时间
119→                log.debug("收到pong响应: {}", session.getId());
120→            }
121→        } catch (IOException e) {
122→            log.error("发送心跳响应失败: {}", e.getMessage(), e);
123→        }
124→    }
