130→    @Override
131→    public void handleTransportError(WebSocketSession session, Throwable exception) throws Exception {
132→        log.warn("handleTransportError:{};exception:{}", session, exception);
133→        if (session.isOpen()) {
134→            session.close();
135→        }
136→        closeConn(session, true);
