275→//    private static void sendMessageToAllUser(ConcurrentHashMap<String, WSUserModel> userMap, String content) {
276→//        if (userMap != null && content != null) {
277→//            TextMessage message = new TextMessage(content);
278→//            userMap.forEach((k, v) -> {
