290→
291→    /**
292→     * 当有用户连接时，把用户添加到USER_SOCKET_SESSION_MAP里，并且返回给前端连接成功
293→     *
294→     * @param session
295→     */
296→    private void openConn(WebSocketSession session) {
297→        //创建一个连接窗口，并加入的队列中
298→        WSUserModel ws = new WSUserModel(session);
299→        WSUserModel.webSocketMapAdd(USER_SOCKET_SESSION_MAP, ws);
300→        log.info("有新窗口开始监听 wsId:{}, gridKey:{}", ws.getId(), ws.getGridKey());
301→        try {
302→            WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.success(MessageTypeEnum.CONNECT_SUCCESS.getDesc(), null);
303→            ObjectMapper obj = new ObjectMapper();
304→            String params = obj.writeValueAsString(webSocketResponseModel);
305→            sendMessageToWs(session, params);
306→
307→        } catch (Exception e) {
308→            log.error("openConn--Exception:" + e);
309→        }
310→    }
311→
312→
313→    private void closeConn(WebSocketSession session, boolean isError) {
314→        WSUserModel wsUserModel = new WSUserModel(session);
315→        WSUserModel.webSocketMapRemove(USER_SOCKET_SESSION_MAP, wsUserModel);
316→
317→        if (isError) {
318→            log.info("窗口关闭(Error) wsId:{}, gridKey:{}", wsUserModel.getId(), wsUserModel.getGridKey());
319→        } else {
320→            log.info("窗口关闭 wsId:{}, gridKey:{}", wsUserModel.getId(), wsUserModel.getGridKey());
321→            try {
322→                WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.success(MessageTypeEnum.CONNECT_CLOSE.getDesc(), null);
323→                ObjectMapper obj = new ObjectMapper();
324→                String params = obj.writeValueAsString(webSocketResponseModel);
325→                sendMessageToWs(session, params);
326→            } catch (Exception ex) {
327→                log.error("closeConn--Exception:" + ex);
328→            }
329→        }
330→
331→    }
