  5→/**
  6→ * 通用返回给前端的websocket数据结构
  7→ */
  8→@Data
  9→public class WebSocketResponseModel {
 10→
 11→    private String message;
 12→    private int status;
 13→    private String type;
 14→    private Object data;
 15→
 16→    // 私有构造函数，强制使用builder
 17→    private WebSocketResponseModel() {}
 18→
 19→    private WebSocketResponseModel(String message, int status, String type, Object data) {
 20→        this.message = message;
 21→        this.status = status;
 22→        this.type = type;
 23→        this.data = data;
 24→    }
 25→
 26→    /**
 27→     * 创建构建器
 28→     */
 29→    public static Builder builder() {
 30→        return new Builder();
 31→    }
 32→
 33→    /**
 34→     * 快速创建成功响应
 35→     */
 36→    public static WebSocketResponseModel success(String message, Object data) {
 37→        return builder()
 38→                .message(message)
 39→                .status(200)
 40→                .type(MessageTypeEnum.CONNECT_SUCCESS.getType())
 41→                .data(data)
 42→                .build();
 43→    }
 44→
 45→    /**
 46→     * 快速创建错误响应
 47→     */
 48→    public static WebSocketResponseModel error(String message, int status) {
 49→        return builder()
 50→                .message(message)
 51→                .status(status)
 52→                .type(MessageTypeEnum.CONNECT_ERROR.getType())
 53→                .build();
 54→    }
 55→
 56→
 57→    /**
 58→     * 快速创建心跳响应
 59→     */
 60→    public static WebSocketResponseModel heartbeat() {
 61→        return builder()
 62→                .message("pong")
 63→                .status(200)
 64→                .type(MessageTypeEnum.CONNECT_HEART.getType())
 65→                .build();
 66→    }
 67→
 68→    /**
 69→     * 构建器类
 70→     */
 71→    public static class Builder {
 72→        private String message;
 73→        private int status;
 74→        private String type;
 75→        private Object data;
 76→
 77→        /**
 78→         * 设置消息内容
 79→         */
 80→        public Builder message(String message) {
 81→            this.message = message;
 82→            return this;
 83→        }
 84→
 85→        /**
 86→         * 设置状态码
 87→         */
 88→        public Builder status(int status) {
 89→            this.status = status;
 90→            return this;
 91→        }
 92→
 93→        /**
 94→         * 设置类型
 95→         */
 96→        public Builder type(String type) {
 97→            this.type = type;
 98→            return this;
 99→        }
100→
101→        /**
102→         * 设置数据
103→         */
104→        public Builder data(Object data) {
105→            this.data = data;
106→            return this;
107→        }
108→
109→        /**
110→         * 构建最终对象
111→         */
112→        public WebSocketResponseModel build() {
113→            return new WebSocketResponseModel(message, status, type, data);
114→        }
115→    }
116→
117→}
