120→    @Override
121→    @Transactional
122→    public void unsubscribe(Long userId, Long spaceNodeId) {
123→        DocSubscriptionEntity existing = docSubscriptionService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
124→        if (existing == null) {
125→            log.info("{} 未订阅，跳过取消 userId={} spaceNodeId={}", LOG_PREFIX, userId, spaceNodeId);
126→            return;
127→        }
128→        docSubscriptionService.removeById(existing);
129→        log.info("{} 取消订阅成功 userId={} spaceNodeId={}", LOG_PREFIX, userId, spaceNodeId);
130→    }
