132→    @Override
133→    @Transactional
134→    public void batchUnsubscribe(Long userId, List<Long> spaceNodeIds) {
135→        List<DocSubscriptionEntity> existingList = docSubscriptionService.listByUserIdAndSpaceNodeIds(userId, spaceNodeIds);
136→        if (existingList.isEmpty()) {
137→            log.info("{} 批量取消订阅：无匹配记录 userId={}", LOG_PREFIX, userId);
138→            return;
139→        }
