145→    @Override
146→    public IPage<SubscriptionListVo> listSubscriptions(Long userId, int pageNum, int pageSize) {
147→        IPage<DocSubscriptionEntity> entityPage = docSubscriptionService.pageByUserId(userId, pageNum, pageSize);
148→
149→        List<Long> nodeIds = entityPage.getRecords().stream()
150→                .map(DocSubscriptionEntity::getSpaceNodeId)
151→                .collect(Collectors.toList());
152→
153→        // 批量加载节点信息
154→        Map<Long, SpaceNodeEntity> nodeMap = new HashMap<>();
155→        if (!nodeIds.isEmpty()) {
156→            List<SpaceNodeEntity> nodes = spaceNodeService.listByIds(nodeIds);
157→            nodeMap = nodes.stream().collect(Collectors.toMap(SpaceNodeEntity::getId, n -> n));
158→        }
159→
160→        Map<Long, SpaceNodeEntity> finalNodeMap = nodeMap;
161→        List<SubscriptionListVo> voList = entityPage.getRecords().stream()
162→                .map(entity -> {
163→                    SpaceNodeEntity node = finalNodeMap.get(entity.getSpaceNodeId());
164→                    // 节点已删除时展示占位名称
165→                    String name = node != null ? node.getName() : "[已删除]";
166→                    String icon = node != null ? node.getIcon() : null;
167→                    Integer type = node != null ? node.getType() : null;
168→                    LocalDateTime updatedAt = node != null ? node.getUpdatedAt() : null;
169→                    return SubscriptionListVo.builder()
170→                            .id(entity.getId())
171→                            .spaceNodeId(entity.getSpaceNodeId())
172→                            .name(name)
173→                            .icon(icon)
174→                            .type(type)
175→                            .subscribedAt(entity.getCreatedAt())
176→                            .updatedAt(updatedAt)
177→                            .build();
178→                })
179→                .collect(Collectors.toList());
180→
181→        // 构造结果分页对象，复用原分页元数据
182→        IPage<SubscriptionListVo> resultPage = new Page<>(entityPage.getCurrent(), entityPage.getSize(), entityPage.getTotal());
183→        resultPage.setRecords(voList);
184→        return resultPage;
185→    }
