187→    @Override
188→    public SubscriptionCheckVo checkSubscriptions(Long userId, List<Long> spaceNodeIds) {
189→        List<DocSubscriptionEntity> existingList = docSubscriptionService.listByUserIdAndSpaceNodeIds(userId, spaceNodeIds);
190→        Set<Long> subscribedIds = existingList.stream()
191→                .map(DocSubscriptionEntity::getSpaceNodeId)
192→                .collect(Collectors.toSet());
193→
194→        // 用 String key 避免前端 Long 精度丢失
195→        Map<String, Boolean> result = new HashMap<>(spaceNodeIds.size());
196→        for (Long nodeId : spaceNodeIds) {
197→            result.put(String.valueOf(nodeId), subscribedIds.contains(nodeId));
198→        }
199→        return SubscriptionCheckVo.builder().subscribed(result).build();
200→    }
