package com.yottastudios.ns.collabspace.subscription.mq;

import cn.hutool.json.JSONUtil;
import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
import com.yottastudios.ns.collabspace.shared.filter.MDCFilter;
import com.yottastudios.ns.collabspace.shared.mq.RabbitMqSender;
import com.yottastudios.ns.collabspace.subscription.mq.dto.DocSubscriptionNotifyMsg;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.slf4j.MDC;
import org.springframework.stereotype.Component;
import org.springframework.transaction.support.TransactionSynchronization;
import org.springframework.transaction.support.TransactionSynchronizationManager;

/**
 * 向订阅通知队列发布文档更新消息。
 * 发送时机：事务提交后（afterCommit），避免 DB 未提交即发 MQ。
 */
@Slf4j
@Component
public class DocSubscriptionNotifyPublisher {

    @Resource
    private RabbitMqSender rabbitMqSender;

    /**
     * 发布文档更新通知消息。
     * 若当前不在事务中，则直接发送。
     *
     * @param spaceNode  发生变更的文档节点
     * @param operatorId 操作人 ID（通知时排除该用户），可为 null
     */
    public void publishDocUpdate(SpaceNodeEntity spaceNode, Long operatorId) {
        if (spaceNode == null) {
            return;
        }
        String traceId = MDC.get(MDCFilter.TRACE_ID);
        DocSubscriptionNotifyMsg msg = DocSubscriptionNotifyMsg.builder()
                .spaceNodeId(spaceNode.getId())
                .spaceNodeName(spaceNode.getName())
                .spaceId(spaceNode.getSpaceId())
                .spaceNodeType(spaceNode.getType())
                .operatorId(operatorId)
                .traceId(traceId)
                .build();

        String msgJson = JSONUtil.toJsonStr(msg);

        if (TransactionSynchronizationManager.isActualTransactionActive()) {
            TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
                @Override
                public void afterCommit() {
                    doSend(msgJson, spaceNode.getId());
                }
            });
        } else {
            doSend(msgJson, spaceNode.getId());
        }
    }

    private void doSend(String msgJson, Long spaceNodeId) {
        try {
            rabbitMqSender.directSend(
                    QueueConfig.DOC_SUBSCRIPTION_NOTIFY_EXCHANGE,
                    QueueConfig.DOC_SUBSCRIPTION_NOTIFY_KEY,
                    msgJson
            );
            log.info("[订阅通知] 已发布文档更新通知 spaceNodeId={}", spaceNodeId);
        } catch (Exception e) {
            log.error("[订阅通知] 发布文档更新通知失败 spaceNodeId={}", spaceNodeId, e);
        }
    }
}

