package com.yottastudios.ns.collabspace.subscription.manager.impl;

import cn.hutool.json.JSONUtil;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
import com.yottastudios.ns.collabspace.subscription.entity.DocSubscriptionEntity;
import com.yottastudios.ns.collabspace.subscription.entity.DocSubscriptionNotificationEntity;
import com.yottastudios.ns.collabspace.subscription.manager.DocSubscriptionNotifyManager;
import com.yottastudios.ns.collabspace.subscription.mq.dto.DocSubscriptionNotifyMsg;
import com.yottastudios.ns.collabspace.subscription.ro.NotificationQueryRo;
import com.yottastudios.ns.collabspace.subscription.service.IDocSubscriptionNotificationService;
import com.yottastudios.ns.collabspace.subscription.service.IDocSubscriptionService;
import com.yottastudios.ns.collabspace.subscription.vo.SubscriptionNotificationVo;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeUserRoleCacheQueryManager;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.data.redis.core.StringRedisTemplate;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.concurrent.TimeUnit;
import java.util.stream.Collectors;

@Slf4j
@Service
public class DocSubscriptionNotifyManagerImpl implements DocSubscriptionNotifyManager {

    private static final String LOG_PREFIX = "[订阅通知]";
    /** 单次推送节流 key 前缀，TTL 300s，防止同一文档对同一用户重复推送 */
    private static final String THROTTLE_KEY_PREFIX = "subscription:throttle:";
    /** IM 发送次数计数 key 前缀，TTL 300s，超过 10 次聚合推送 */
    private static final String IM_COUNT_KEY_PREFIX = "subscription:im_count:";
    private static final long THROTTLE_TTL_SECONDS = 300L;
    private static final long IM_COUNT_TTL_SECONDS = 300L;
    private static final long IM_COUNT_AGGREGATE_THRESHOLD = 10L;

    @Value("${subscription.im.channel:none}")
    private String imChannel;

    @Value("${subscription.collabspace.url:}")
    private String collabspaceUrl;

    @Resource
    private IDocSubscriptionService docSubscriptionService;

    @Resource
    private IDocSubscriptionNotificationService docSubscriptionNotificationService;

    @Resource
    private SpaceNodeUserRoleCacheQueryManager spaceNodeUserRoleCacheQueryManager;

    @Resource
    private WebSocketHandler webSocketHandler;

    @Resource
    private StringRedisTemplate stringRedisTemplate;

    @Resource
    private ObjectMapper objectMapper;

    @Override
    public void handleDocUpdate(DocSubscriptionNotifyMsg msg) {
        Long spaceNodeId = msg.getSpaceNodeId();
        String spaceNodeName = msg.getSpaceNodeName();
        Long operatorId = msg.getOperatorId();
        String traceId = msg.getTraceId();

        // 1. 查询订阅该文档的所有用户
        List<DocSubscriptionEntity> subscribers = docSubscriptionService.listBySpaceNodeId(spaceNodeId);
        if (subscribers.isEmpty()) {
            log.info("{} 无订阅者，跳过 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
            return;
        }

        // 2. 过滤掉操作人自身
        Set<Long> subscriberIds = subscribers.stream()
                .map(DocSubscriptionEntity::getUserId)
                .collect(Collectors.toSet());
        if (operatorId != null) {
            subscriberIds.remove(operatorId);
        }
        if (subscriberIds.isEmpty()) {
            log.info("{} 过滤操作人后无订阅者 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
            return;
        }

        // 3. 权限校验：取与有读权限用户的交集
        List<Long> permittedUserIds = spaceNodeUserRoleCacheQueryManager
                .listUserIdsBySpaceNodeIdsAndMinRole(List.of(spaceNodeId), NodeRoleLevel.READER);
        Set<Long> permittedSet = new HashSet<>(permittedUserIds);
        subscriberIds.retainAll(permittedSet);
        if (subscriberIds.isEmpty()) {
            log.info("{} 权限校验后无目标用户 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
            return;
        }

        // 4. 逐用户处理：节流 + 保存通知 + IM 推送
        List<Long> notifiedUserIds = new ArrayList<>();
        for (Long userId : subscriberIds) {
            // 4a. Redis 节流：同一文档同一用户 300s 内只推一次
            String throttleKey = THROTTLE_KEY_PREFIX + spaceNodeId + ":" + userId;
            Boolean isFirstPush = stringRedisTemplate.opsForValue()
                    .setIfAbsent(throttleKey, "1", THROTTLE_TTL_SECONDS, TimeUnit.SECONDS);
            if (!Boolean.TRUE.equals(isFirstPush)) {
                log.debug("{} 节流跳过 spaceNodeId={} userId={}", LOG_PREFIX, spaceNodeId, userId);
                continue;
            }

            // 4b. 保存通知记录
            DocSubscriptionNotificationEntity notification = DocSubscriptionNotificationEntity.builder()
                    .userId(userId)
                    .spaceNodeId(spaceNodeId)
                    .spaceNodeName(spaceNodeName)
                    .isRead(0)
                    .build();
            docSubscriptionNotificationService.save(notification);

            // 4c. IM 推送计数与分发
            String imCountKey = IM_COUNT_KEY_PREFIX + userId;
            Long imCount = stringRedisTemplate.opsForValue().increment(imCountKey);
            if (imCount == null) {
                imCount = 1L;
            }
            if (imCount == 1L) {
                // 首次计数，设置 TTL
                stringRedisTemplate.expire(imCountKey, IM_COUNT_TTL_SECONDS, TimeUnit.SECONDS);
            }

            if (imCount > IM_COUNT_AGGREGATE_THRESHOLD) {
                // 超过 10 次，跳过单独推送（聚合消息已在第 10 次发出）
                log.debug("{} IM 计数超阈值，跳过单独推送 userId={} count={}", LOG_PREFIX, userId, imCount);
            } else if (imCount.equals(IM_COUNT_AGGREGATE_THRESHOLD)) {
                // 第 10 次：发送聚合提示消息
                sendAggregateImMsg(userId, traceId);
            } else {
                // 1~9 次：发送正常单条消息
                sendNormalImMsg(userId, spaceNodeId, spaceNodeName, traceId);
            }

            notifiedUserIds.add(userId);
        }

        // 5. WebSocket 推送给所有命中用户
        if (!notifiedUserIds.isEmpty()) {
            pushViaWebSocket(notifiedUserIds, spaceNodeId, spaceNodeName, traceId);
        }

        log.info("{} 处理完成 spaceNodeId={} notifiedCount={} traceId={}",
                LOG_PREFIX, spaceNodeId, notifiedUserIds.size(), traceId);
    }

    /**
     * WebSocket 推送订阅更新事件
     */
    private void pushViaWebSocket(List<Long> userIds, Long spaceNodeId, String spaceNodeName, String traceId) {
        try {
            WebSocketResponseModel responseModel = WebSocketResponseModel.builder()
                    .message(MessageTypeEnum.SUBSCRIPTION_UPDATE.getDesc())
                    .status(200)
                    .type(MessageTypeEnum.SUBSCRIPTION_UPDATE.getType())
                    .data(new java.util.HashMap<String, Object>() {{
                        put("spaceNodeId", String.valueOf(spaceNodeId));
                        put("spaceNodeName", spaceNodeName);
                    }})
                    .build();
            String wsMsg = objectMapper.writeValueAsString(responseModel);
            int sent = webSocketHandler.sendUsersToWebSocketClient(wsMsg, userIds);
            log.info("{} WebSocket 推送完成 spaceNodeId={} targetCount={} actualSent={} traceId={}",
                    LOG_PREFIX, spaceNodeId, userIds.size(), sent, traceId);
        } catch (Exception e) {
            log.error("{} WebSocket 推送失败 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId, e);
        }
    }

    /**
     * 发送正常 IM 单条通知
     * TODO: implement in Task 8
     */
    private void sendNormalImMsg(Long userId, Long spaceNodeId, String spaceNodeName, String traceId) {
        log.info("{} [TODO-Task8] 发送 IM 单条通知 channel={} userId={} spaceNodeId={} traceId={}",
                LOG_PREFIX, imChannel, userId, spaceNodeId, traceId);
        // TODO: implement in Task 8
    }

    /**
     * 发送 IM 聚合提示消息（当短时间内通知数超过阈值时）
     * TODO: implement in Task 8
     */
