 37→
 38→    private static final String LOG_PREFIX = "[订阅通知]";
 39→    /** 单次推送节流 key 前缀，TTL 300s，防止同一文档对同一用户重复推送 */
 40→    private static final String THROTTLE_KEY_PREFIX = "subscription:throttle:";
 41→    /** IM 发送次数计数 key 前缀，TTL 300s，超过 10 次聚合推送 */
 42→    private static final String IM_COUNT_KEY_PREFIX = "subscription:im_count:";
 43→    private static final long THROTTLE_TTL_SECONDS = 300L;
 44→    private static final long IM_COUNT_TTL_SECONDS = 300L;
 45→    private static final long IM_COUNT_AGGREGATE_THRESHOLD = 10L;
 46→
 47→    @Value("${subscription.im.channel:none}")
 48→    private String imChannel;
 49→
 50→    @Value("${subscription.collabspace.url:}")
 51→    private String collabspaceUrl;
