165→    private void pushViaWebSocket(List<Long> userIds, Long spaceNodeId, String spaceNodeName, String traceId) {
166→        try {
167→            Map<String, Object> payload = new HashMap<>(4);
168→            payload.put("spaceNodeId", String.valueOf(spaceNodeId));
169→            payload.put("spaceNodeName", spaceNodeName);
170→            WebSocketResponseModel responseModel = WebSocketResponseModel.builder()
171→                    .message(MessageTypeEnum.SUBSCRIPTION_UPDATE.getDesc())
172→                    .status(200)
173→                    .type(MessageTypeEnum.SUBSCRIPTION_UPDATE.getType())
174→                    .data(payload)
175→                    .build();
176→            String wsMsg = objectMapper.writeValueAsString(responseModel);
177→            int sent = webSocketHandler.sendUsersToWebSocketClient(wsMsg, userIds);
178→            log.info("{} WebSocket 推送完成 spaceNodeId={} targetCount={} actualSent={} traceId={}",
179→                    LOG_PREFIX, spaceNodeId, userIds.size(), sent, traceId);
180→        } catch (Exception e) {
181→            log.error("{} WebSocket 推送失败 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId, e);
182→        }
183→    }
